INSERT INTO `v1_15b32b7d6d2d5af46b10463fcf3b9788fe4b746ec57e74b4f3944c831605dd83` VALUES (1, "加速", "ＴＰ回復や行動速度アップにより、キャラのスキルやユニオンバーストの発動数が増加する\n", "【加速】");
INSERT INTO `v1_15b32b7d6d2d5af46b10463fcf3b9788fe4b746ec57e74b4f3944c831605dd83` VALUES (2, "弱体", "敵に継続ダメージ系状態異常や弱体効果を付与し、敵を弱体化させる\n", "【弱体】");
INSERT INTO `v1_15b32b7d6d2d5af46b10463fcf3b9788fe4b746ec57e74b4f3944c831605dd83` VALUES (3, "会心", "クリティカルや通常攻撃強化により、攻撃性能を強化する\n", "【会心】");
INSERT INTO `v1_15b32b7d6d2d5af46b10463fcf3b9788fe4b746ec57e74b4f3944c831605dd83` VALUES (4, "強化", "攻撃力や防御力アップのバフ効果を用いて、キャラを強化する\n", "【強化】");
INSERT INTO `v1_15b32b7d6d2d5af46b10463fcf3b9788fe4b746ec57e74b4f3944c831605dd83` VALUES (5, "守備", "ＨＰアップやバリア展開により、耐久性能を強化する\n", "【守備】");
